import React, { useEffect, useMemo, useRef, useState } from 'react';
import { useI18n } from '../i18n';

/**
 * Screen 12 ΓÇö Active Charging Session (Web)
 *
 * Props:
 *  session: {
 *    startedAt,
 *    kwhDelivered,
 *    powerKw,
 *    ratePerKwh,
 *    mode,
 *    estimatedRemaining,
 *    targetKwh,
 *    stopPin
 *  }
 *  unreadCount
 *  onOpenChat()
 *  onStopCharging(pin)
 *  onEmergencyStop()
 *  onValidateVisibility()
 */
export default function ChargingSessionScreen({
  session = {},
  unreadCount = 0,
  onOpenChat,
  onStopCharging,
  onEmergencyStop,
  onValidateVisibility,
}) {
  const { t, locale } = useI18n();
  const isHindi = locale === 'hi';

  function tx(key, fallback) {
    const v = t(key);
    return v === key ? fallback : v;
  }

  const [elapsedSec, setElapsedSec] = useState(0);
  const [targetKwh, setTargetKwh] = useState(Number(session?.kwhDelivered || 0));
  const [targetPower, setTargetPower] = useState(Number(session?.powerKw || 7.2));
  const [targetCost, setTargetCost] = useState(0);

  const displayKwh = useAnimatedNumber(targetKwh, 550);
  const displayPower = useAnimatedNumber(targetPower, 500);
  const displayCost = useAnimatedNumber(targetCost, 600);

  const [stopOpen, setStopOpen] = useState(false);
  const [stopPin, setStopPin] = useState('');
  const pinRefs = useRef([]);

  const [startedAtFallback] = useState(() => Date.now());
  const startedAtMs = useMemo(() => {
    const raw = session?.startedAt;
    if (!raw) return startedAtFallback;
    const d = raw?.toDate?.() || (raw instanceof Date ? raw : (typeof raw === 'number' ? new Date(raw) : null));
    return d?.getTime?.() || startedAtFallback;
  }, [session?.startedAt, startedAtFallback]);

  useEffect(() => {
    onValidateVisibility?.();
  }, [onValidateVisibility]);

  useEffect(() => {
    // Count up session timer
    const tick = () => {
      const diff = Math.max(0, Math.floor((Date.now() - startedAtMs) / 1000));
      setElapsedSec(diff);
    };
    tick();
    const id = setInterval(tick, 1000);
    return () => clearInterval(id);
  }, [startedAtMs]);

  useEffect(() => {
    // Base values from backend snapshot
    // eslint-disable-next-line react-hooks/set-state-in-effect
    setTargetKwh(Number(session?.kwhDelivered || 0));
    setTargetPower(Number(session?.powerKw || 7.2));
  }, [session?.kwhDelivered, session?.powerKw]);

  useEffect(() => {
    // Live progression every 10s for UI between backend refreshes
    const rate = Number(session?.ratePerKwh || 22);
    // eslint-disable-next-line react-hooks/set-state-in-effect
    setTargetCost(Number(session?.kwhDelivered || 0) * rate);

    const id = setInterval(() => {
      setTargetKwh((prev) => {
        const next = prev + (targetPower / 360); // 10s energy increment
        setTargetCost(next * rate);
        return next;
      });
      // subtle power drift
      setTargetPower((p) => {
        const drift = ((Math.random() * 0.18) - 0.09);
        return Math.max(1.5, p + drift);
      });
    }, 10000);

    return () => clearInterval(id);
  }, [session?.kwhDelivered, session?.ratePerKwh, targetPower]);

  const hhmmss = formatHHMMSS(elapsedSec);
  const ratePerKwh = Number(session?.ratePerKwh || 22);
  const remaining = session?.estimatedRemaining || '00:42:00';
  const mode = session?.mode || 'FAST';
  const targetCapacity = Number(session?.targetKwh || 24);
  const fillPct = Math.max(0, Math.min(100, (displayKwh / Math.max(1, targetCapacity)) * 100));

  function handlePinChange(i, value) {
    const digit = value.replace(/\D/g, '').slice(-1);
    const arr = stopPin.padEnd(4, ' ').split('');
    arr[i] = digit || ' ';
    const next = arr.join('').replace(/\s+$/g, '');
    setStopPin(next);
    if (digit && i < 3) pinRefs.current[i + 1]?.focus();
  }

  function handlePinKeyDown(i, e) {
    if (e.key === 'Backspace' && !stopPin[i] && i > 0) pinRefs.current[i - 1]?.focus();
  }

  function confirmStop() {
    if (stopPin.length !== 4) return;
    onStopCharging?.(stopPin);
    setStopOpen(false);
    setStopPin('');
  }

  return (
    <div style={s.page}>
      <style>{cssText}</style>

      <div style={s.content}>
        {/* Header */}
        <div style={s.header}>
          <div style={s.statusRow}>
            <span style={s.statusDot} />
            <span style={s.statusText}>{tx('charging.active', isHindi ? 'αñ╕αÑçαñ╢αñ¿ αñÜαñ╛αñ▓αÑé' : 'Session Active')}</span>
          </div>
          <div style={s.timer}>{hhmmss}</div>
        </div>

        {/* Main stats card */}
        <div style={s.mainCard}>
          <div style={s.bigStat}>
            <span style={s.bigValue}>{displayKwh.toFixed(2)}</span>
            <span style={s.bigLabel}>kWh {tx('charging.delivered', isHindi ? 'αñíαñ┐αñ▓αÑÇαñ╡αñ░' : 'delivered')}</span>
          </div>

          <div style={s.midStatsRow}>
            <div style={s.midStat}><span style={s.midVal}>{displayPower.toFixed(1)}</span><span style={s.midLbl}>kW</span></div>
            <div style={s.midStat}><span style={s.midVal}>Γé╣{displayCost.toFixed(0)}</span><span style={s.midLbl}>{tx('charging.costSoFar', isHindi ? 'αñàαñ¼ αññαñò' : 'cost so far')}</span></div>
          </div>
        </div>

        {/* Charging animation */}
        <div style={s.batteryWrap}>
          <div style={s.batteryBody}>
            <div style={{ ...s.batteryFill, height: `${fillPct}%` }} />
            <div style={s.boltPulse}>ΓÜí</div>
          </div>
          <div style={s.batteryCap} />
          <div style={s.fillPct}>{Math.round(fillPct)}%</div>
        </div>

        {/* Details row */}
        <div style={s.detailsRow}>
          <MiniCard label={tx('charging.mode', isHindi ? 'αñ«αÑïαñí' : 'Mode')} value={mode} />
          <MiniCard label={tx('charging.rate', isHindi ? 'αñ░αÑçαñƒ' : 'Rate')} value={`Γé╣${ratePerKwh}/kWh`} />
          <MiniCard label={tx('charging.remaining', isHindi ? 'αñ¼αñ╛αñòαÑÇ' : 'Est. remaining')} value={remaining} />
        </div>
      </div>

      {/* Floating chat */}
      <button style={s.chatFab} onClick={() => onOpenChat?.()} aria-label="Chat">
        ≡ƒÆ¼
        {unreadCount > 0 && <span style={s.chatBadge}>{unreadCount > 9 ? '9+' : unreadCount}</span>}
      </button>

      {/* Bottom actions */}
      <div style={s.bottomWrap}>
        <button style={s.stopBtn} onClick={() => setStopOpen(true)}>
          {tx('charging.stop', isHindi ? 'αñÜαñ╛αñ░αÑìαñ£αñ┐αñéαñù αñ░αÑïαñòαÑçαñé' : 'Stop Charging')}
        </button>
        <button style={s.emergencyLink} onClick={() => onEmergencyStop?.()}>
          {tx('charging.emergency', isHindi ? 'αñçαñ«αñ░αñ£αÑçαñéαñ╕αÑÇ αñ╕αÑìαñƒαÑëαñ¬ ΓÇö αñ╣αÑïαñ╕αÑìαñƒ αñæαñ½αñ▓αñ╛αñçαñ¿?' : 'Emergency stop ΓÇö host offline?')}
        </button>
      </div>

      {stopOpen && (
        <div style={s.modalOverlay} onClick={() => setStopOpen(false)}>
          <div style={s.modal} onClick={(e) => e.stopPropagation()}>
            <h3 style={s.modalTitle}>{tx('charging.confirmStop', isHindi ? 'αñòαÑìαñ»αñ╛ αñåαñ¬ αñ╕αÑüαñ¿αñ┐αñ╢αÑìαñÜαñ┐αññ αñ╣αÑêαñé?' : 'Are you sure?')}</h3>
            <p style={s.modalText}>{tx('charging.enterStopPin', isHindi ? 'αñ╕αÑçαñ╢αñ¿ αñûαññαÑìαñ« αñòαñ░αñ¿αÑç αñòαÑç αñ▓αñ┐αñÅ αñ╕αÑìαñƒαÑëαñ¬ PIN αñªαñ░αÑìαñ£ αñòαñ░αÑçαñé' : 'Enter stop PIN to end session')}</p>

            <div style={s.pinRow}>
              {[0, 1, 2, 3].map((i) => {
                const filled = i < stopPin.length;
                return (
                  <div key={i} style={{ ...s.pinBox, borderColor: filled ? '#00D4AA' : 'rgba(255,255,255,0.16)' }}>
                    <div style={{ ...s.pinDot, opacity: filled ? 1 : 0 }} />
                    <input
                      ref={(el) => (pinRefs.current[i] = el)}
                      type="password"
                      inputMode="numeric"
                      maxLength={1}
                      value={filled ? 'ΓÇó' : ''}
                      onChange={(e) => handlePinChange(i, e.target.value)}
                      onKeyDown={(e) => handlePinKeyDown(i, e)}
                      style={s.pinInput}
                    />
                  </div>
                );
              })}
            </div>

            <div style={s.modalActions}>
              <button style={s.modalGhost} onClick={() => setStopOpen(false)}>{tx('common.cancel', isHindi ? 'αñ░αñªαÑìαñª αñòαñ░αÑçαñé' : 'Cancel')}</button>
              <button style={{ ...s.modalDanger, opacity: stopPin.length === 4 ? 1 : 0.4 }} onClick={confirmStop} disabled={stopPin.length !== 4}>
                {tx('charging.endSession', isHindi ? 'αñ╕αÑçαñ╢αñ¿ αñûαññαÑìαñ« αñòαñ░αÑçαñé' : 'End Session')}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

function MiniCard({ label, value }) {
  return (
    <div style={s.miniCard}>
      <span style={s.miniVal}>{value}</span>
      <span style={s.miniLbl}>{label}</span>
    </div>
  );
}

function useAnimatedNumber(target, duration = 600) {
  const [value, setValue] = useState(Number(target) || 0);
  const rafRef = useRef(null);

  useEffect(() => {
    const from = Number(value) || 0;
    const to = Number(target) || 0;
    if (Math.abs(to - from) < 0.0001) return undefined;

    const start = performance.now();
    const easeOut = (x) => 1 - Math.pow(1 - x, 3);

    const tick = (now) => {
      const progress = Math.min(1, (now - start) / duration);
      const eased = easeOut(progress);
      const next = from + (to - from) * eased;
      setValue(next);
      if (progress < 1) rafRef.current = requestAnimationFrame(tick);
    };

    rafRef.current = requestAnimationFrame(tick);
    return () => {
      if (rafRef.current) cancelAnimationFrame(rafRef.current);
    };
  }, [target, duration]);

  return value;
}

function formatHHMMSS(total) {
  const h = String(Math.floor(total / 3600)).padStart(2, '0');
  const m = String(Math.floor((total % 3600) / 60)).padStart(2, '0');
  const s = String(total % 60).padStart(2, '0');
  return `${h}:${m}:${s}`;
}

const cssText = `
  * { box-sizing: border-box; }
  @keyframes dotPulse {
    0%,100% { opacity: 1; transform: scale(1); }
    50% { opacity: .35; transform: scale(.75); }
  }
  @keyframes boltPop {
    0%,100% { transform: scale(1); opacity: 1; }
    50% { transform: scale(1.12); opacity: .75; }
  }
`;

const s = {
  page: {
    minHeight: '100dvh',
    background: '#0A0A0F',
    color: '#fff',
    fontFamily: "'Inter', sans-serif",
    position: 'relative',
  },
  content: {
    padding: '22px 16px 130px',
  },

  header: {
    marginBottom: 14,
  },
  statusRow: {
    display: 'flex',
    alignItems: 'center',
    gap: 8,
    marginBottom: 10,
  },
  statusDot: {
    width: 8,
    height: 8,
    borderRadius: '50%',
    background: '#22C55E',
    animation: 'dotPulse 1.2s ease-in-out infinite',
  },
  statusText: {
    fontSize: 13,
    color: '#22C55E',
    fontWeight: 700,
