import React, { useEffect, useMemo, useRef, useState } from 'react';
import {
  Animated,
  Easing,
  Modal,
  StyleSheet,
  Text,
  TextInput,
  TouchableOpacity,
  View,
} from 'react-native';
import { useI18n } from '../i18n';

/**
 * Screen 12 ΓÇö Active Charging Session (Native)
 * Props mirror web variant.
 */
export default function ChargingSessionScreen({
  session = {},
  unreadCount = 0,
  onOpenChat,
  onStopCharging,
  onEmergencyStop,
  onValidateVisibility,
}) {
  const { t, locale } = useI18n();
  const isHindi = locale === 'hi';

  function tx(key, fallback) {
    const v = t(key);
    return v === key ? fallback : v;
  }

  const [elapsedSec, setElapsedSec] = useState(0);
  const [targetKwh, setTargetKwh] = useState(Number(session?.kwhDelivered || 0));
  const [targetPower, setTargetPower] = useState(Number(session?.powerKw || 7.2));
  const [targetCost, setTargetCost] = useState(0);

  const displayKwh = useAnimatedNumber(targetKwh, 550);
  const displayPower = useAnimatedNumber(targetPower, 500);
  const displayCost = useAnimatedNumber(targetCost, 600);

  const [stopOpen, setStopOpen] = useState(false);
  const [stopPin, setStopPin] = useState('');

  const [dotPulse] = useState(() => new Animated.Value(1));
  const [boltPulse] = useState(() => new Animated.Value(1));

  const [startedAtFallback] = useState(() => Date.now());
  const startedAtMs = useMemo(() => {
    const raw = session?.startedAt;
    if (!raw) return startedAtFallback;
    const d = raw?.toDate?.() || (raw instanceof Date ? raw : (typeof raw === 'number' ? new Date(raw) : null));
    return d?.getTime?.() || startedAtFallback;
  }, [session?.startedAt, startedAtFallback]);

  useEffect(() => {
    onValidateVisibility?.();
  }, [onValidateVisibility]);

  useEffect(() => {
    const tick = () => {
      const diff = Math.max(0, Math.floor((Date.now() - startedAtMs) / 1000));
      setElapsedSec(diff);
    };
    tick();
    const id = setInterval(tick, 1000);
    return () => clearInterval(id);
  }, [startedAtMs]);

  useEffect(() => {
    // eslint-disable-next-line react-hooks/set-state-in-effect
    setTargetKwh(Number(session?.kwhDelivered || 0));
    setTargetPower(Number(session?.powerKw || 7.2));
  }, [session?.kwhDelivered, session?.powerKw]);

  useEffect(() => {
    const rate = Number(session?.ratePerKwh || 22);
    // eslint-disable-next-line react-hooks/set-state-in-effect
    setTargetCost(Number(session?.kwhDelivered || 0) * rate);

    const id = setInterval(() => {
      setTargetKwh((prev) => {
        const next = prev + (targetPower / 360);
        setTargetCost(next * rate);
        return next;
      });
      setTargetPower((p) => {
        const drift = ((Math.random() * 0.18) - 0.09);
        return Math.max(1.5, p + drift);
      });
    }, 10000);

    return () => clearInterval(id);
  }, [session?.kwhDelivered, session?.ratePerKwh, targetPower]);

  useEffect(() => {
    const d = Animated.loop(
      Animated.sequence([
        Animated.timing(dotPulse, { toValue: 0.35, duration: 600, useNativeDriver: true }),
        Animated.timing(dotPulse, { toValue: 1, duration: 600, useNativeDriver: true }),
      ])
    );
    const b = Animated.loop(
      Animated.sequence([
        Animated.timing(boltPulse, { toValue: 1.12, duration: 550, easing: Easing.inOut(Easing.quad), useNativeDriver: true }),
        Animated.timing(boltPulse, { toValue: 1, duration: 550, easing: Easing.inOut(Easing.quad), useNativeDriver: true }),
      ])
    );
    d.start();
    b.start();
    return () => {
      d.stop();
      b.stop();
    };
  }, [dotPulse, boltPulse]);

  const hhmmss = formatHHMMSS(elapsedSec);
  const ratePerKwh = Number(session?.ratePerKwh || 22);
  const remaining = session?.estimatedRemaining || '00:42:00';
  const mode = session?.mode || 'FAST';
  const targetCapacity = Number(session?.targetKwh || 24);
  const fillPct = Math.max(0, Math.min(100, (displayKwh / Math.max(1, targetCapacity)) * 100));

  function handleStopPinChange(text) {
    const digits = text.replace(/\D/g, '').slice(0, 4);
    setStopPin(digits);
  }

  function confirmStop() {
    if (stopPin.length !== 4) return;
    onStopCharging?.(stopPin);
    setStopOpen(false);
    setStopPin('');
  }

  return (
    <View style={s.page}>
      <View style={s.content}>
        {/* Header */}
        <View style={s.header}>
          <View style={s.statusRow}>
            <Animated.View style={[s.statusDot, { opacity: dotPulse, transform: [{ scale: dotPulse }] }]} />
            <Text style={s.statusText}>{tx('charging.active', isHindi ? 'αñ╕αÑçαñ╢αñ¿ αñÜαñ╛αñ▓αÑé' : 'Session Active')}</Text>
          </View>
          <Text style={s.timer}>{hhmmss}</Text>
        </View>

        {/* Main stats */}
        <View style={s.mainCard}>
          <View style={s.bigStat}>
            <Text style={s.bigValue}>{displayKwh.toFixed(2)}</Text>
            <Text style={s.bigLabel}>kWh {tx('charging.delivered', isHindi ? 'αñíαñ┐αñ▓αÑÇαñ╡αñ░' : 'delivered')}</Text>
          </View>

          <View style={s.midStatsRow}>
            <View style={s.midStat}>
              <Text style={s.midVal}>{displayPower.toFixed(1)}</Text>
              <Text style={s.midLbl}>kW</Text>
            </View>
            <View style={s.midStat}>
              <Text style={s.midVal}>Γé╣{displayCost.toFixed(0)}</Text>
              <Text style={s.midLbl}>{tx('charging.costSoFar', isHindi ? 'αñàαñ¼ αññαñò' : 'cost so far')}</Text>
            </View>
          </View>
        </View>

        {/* Charging animation */}
        <View style={s.batteryWrap}>
          <View style={s.batteryBody}>
            <View style={[s.batteryFill, { height: `${fillPct}%` }]} />
            <Animated.Text style={[s.boltPulse, { transform: [{ scale: boltPulse }] }]}>ΓÜí</Animated.Text>
          </View>
          <View style={s.batteryCap} />
          <Text style={s.fillPct}>{Math.round(fillPct)}%</Text>
        </View>

        {/* Details */}
        <View style={s.detailsRow}>
          <MiniCard label={tx('charging.mode', isHindi ? 'αñ«αÑïαñí' : 'Mode')} value={mode} />
          <MiniCard label={tx('charging.rate', isHindi ? 'αñ░αÑçαñƒ' : 'Rate')} value={`Γé╣${ratePerKwh}/kWh`} />
          <MiniCard label={tx('charging.remaining', isHindi ? 'αñ¼αñ╛αñòαÑÇ' : 'Est. remaining')} value={remaining} />
        </View>
      </View>

      {/* Chat FAB */}
      <TouchableOpacity style={s.chatFab} onPress={() => onOpenChat?.()} activeOpacity={0.85}>
        <Text style={s.chatFabText}>≡ƒÆ¼</Text>
        {unreadCount > 0 ? <View style={s.chatBadge}><Text style={s.chatBadgeText}>{unreadCount > 9 ? '9+' : unreadCount}</Text></View> : null}
      </TouchableOpacity>

      {/* Bottom */}
      <View style={s.bottomWrap}>
        <TouchableOpacity style={s.stopBtn} onPress={() => setStopOpen(true)} activeOpacity={0.85}>
          <Text style={s.stopBtnText}>{tx('charging.stop', isHindi ? 'αñÜαñ╛αñ░αÑìαñ£αñ┐αñéαñù αñ░αÑïαñòαÑçαñé' : 'Stop Charging')}</Text>
        </TouchableOpacity>
        <TouchableOpacity onPress={() => onEmergencyStop?.()} activeOpacity={0.7}>
          <Text style={s.emergencyLink}>{tx('charging.emergency', isHindi ? 'αñçαñ«αñ░αñ£αÑçαñéαñ╕αÑÇ αñ╕αÑìαñƒαÑëαñ¬ ΓÇö αñ╣αÑïαñ╕αÑìαñƒ αñæαñ½αñ▓αñ╛αñçαñ¿?' : 'Emergency stop ΓÇö host offline?')}</Text>
        </TouchableOpacity>
      </View>

      <Modal visible={stopOpen} transparent animationType="fade" onRequestClose={() => setStopOpen(false)}>
        <View style={s.modalOverlay}>
          <View style={s.modal}>
            <Text style={s.modalTitle}>{tx('charging.confirmStop', isHindi ? 'αñòαÑìαñ»αñ╛ αñåαñ¬ αñ╕αÑüαñ¿αñ┐αñ╢αÑìαñÜαñ┐αññ αñ╣αÑêαñé?' : 'Are you sure?')}</Text>
            <Text style={s.modalText}>{tx('charging.enterStopPin', isHindi ? 'αñ╕αÑçαñ╢αñ¿ αñûαññαÑìαñ« αñòαñ░αñ¿αÑç αñòαÑç αñ▓αñ┐αñÅ αñ╕αÑìαñƒαÑëαñ¬ PIN αñªαñ░αÑìαñ£ αñòαñ░αÑçαñé' : 'Enter stop PIN to end session')}</Text>

            <View style={s.pinRow}>
              {[0, 1, 2, 3].map((i) => {
                const filled = i < stopPin.length;
                return (
                  <View key={i} style={[s.pinBox, filled && s.pinBoxFilled]}>
                    <View style={[s.pinDot, { opacity: filled ? 1 : 0 }]} />
                  </View>
                );
              })}
            </View>

            <TextInput
              value={stopPin}
              onChangeText={handleStopPinChange}
              keyboardType="number-pad"
              maxLength={4}
              secureTextEntry
              autoFocus
              style={s.hiddenPinInput}
            />

            <View style={s.modalActions}>
              <TouchableOpacity style={s.modalGhost} onPress={() => setStopOpen(false)} activeOpacity={0.85}>
                <Text style={s.modalGhostText}>{tx('common.cancel', isHindi ? 'αñ░αñªαÑìαñª αñòαñ░αÑçαñé' : 'Cancel')}</Text>
              </TouchableOpacity>
              <TouchableOpacity style={[s.modalDanger, { opacity: stopPin.length === 4 ? 1 : 0.4 }]} onPress={confirmStop} disabled={stopPin.length !== 4} activeOpacity={0.85}>
                <Text style={s.modalDangerText}>{tx('charging.endSession', isHindi ? 'αñ╕αÑçαñ╢αñ¿ αñûαññαÑìαñ« αñòαñ░αÑçαñé' : 'End Session')}</Text>
              </TouchableOpacity>
            </View>
          </View>
        </View>
      </Modal>
    </View>
  );
}

function MiniCard({ label, value }) {
  return (
    <View style={s.miniCard}>
      <Text style={s.miniVal}>{value}</Text>
      <Text style={s.miniLbl}>{label}</Text>
    </View>
  );
}

function useAnimatedNumber(target, duration = 600) {
  const [value, setValue] = useState(Number(target) || 0);
  const animRef = useRef(new Animated.Value(Number(target) || 0));

  useEffect(() => {
    const to = Number(target) || 0;
    const listener = animRef.current.addListener(({ value: v }) => setValue(v));
    Animated.timing(animRef.current, {
      toValue: to,
      duration,
      easing: Easing.out(Easing.cubic),
      useNativeDriver: false,
    }).start();
    return () => {
      animRef.current.removeListener(listener);
    };
  }, [target, duration]);

  return value;
}

function formatHHMMSS(total) {
  const h = String(Math.floor(total / 3600)).padStart(2, '0');
  const m = String(Math.floor((total % 3600) / 60)).padStart(2, '0');
  const s = String(total % 60).padStart(2, '0');
  return `${h}:${m}:${s}`;
}

const s = StyleSheet.create({
  page: {
    flex: 1,
    backgroundColor: '#0A0A0F',
  },
  content: {
    paddingHorizontal: 16,
    paddingTop: 22,
    paddingBottom: 130,
  },

  header: { marginBottom: 14 },
  statusRow: { flexDirection: 'row', alignItems: 'center', gap: 8, marginBottom: 10 },
  statusDot: { width: 8, height: 8, borderRadius: 4, backgroundColor: '#22C55E' },
  statusText: {
    fontSize: 13,
    color: '#22C55E',
    fontWeight: '700',
    textTransform: 'uppercase',
    letterSpacing: 0.5,
  },
  timer: {
    fontSize: 38,
    fontWeight: '800',
    letterSpacing: 1.2,
    color: '#fff',
  },

  mainCard: {
    borderRadius: 16,
    borderWidth: 1,
    borderColor: 'rgba(255,255,255,0.11)',
    backgroundColor: 'rgba(0,212,170,0.08)',
    padding: 14,
    marginBottom: 16,
  },
  bigStat: { marginBottom: 10 },
  bigValue: {
    fontSize: 44,
    lineHeight: 46,
    fontWeight: '800',
    color: '#00D4AA',
  },
  bigLabel: {
    marginTop: 4,
    fontSize: 13,
    color: 'rgba(255,255,255,0.6)',
  },
  midStatsRow: { flexDirection: 'row', gap: 10 },
  midStat: {
    flex: 1,
    borderRadius: 12,
    borderWidth: 1,
    borderColor: 'rgba(255,255,255,0.09)',
    backgroundColor: 'rgba(255,255,255,0.03)',
    padding: 10,
  },
  midVal: { fontSize: 22, fontWeight: '700', color: '#fff' },
  midLbl: { marginTop: 2, fontSize: 11, color: 'rgba(255,255,255,0.56)' },

  batteryWrap: {
    marginBottom: 16,
    alignItems: 'center',
  },
  batteryBody: {
    width: 118,
    height: 178,
    borderRadius: 14,
    borderWidth: 2,
    borderColor: 'rgba(255,255,255,0.22)',
    backgroundColor: 'rgba(255,255,255,0.03)',
    overflow: 'hidden',
    alignItems: 'center',
    justifyContent: 'center',
  },
  batteryFill: {
    position: 'absolute',
    left: 0,
    right: 0,
    bottom: 0,
    backgroundColor: '#00D4AA',
  },
  boltPulse: {
    color: '#fff',
    fontSize: 34,
    fontWeight: '700',
  },
  batteryCap: {
    width: 42,
    height: 8,
    borderRadius: 4,
    backgroundColor: 'rgba(255,255,255,0.22)',
    marginTop: 6,
  },
  fillPct: { marginTop: 8, color: '#00D4AA', fontWeight: '700', fontSize: 14 },

  detailsRow: { flexDirection: 'row', gap: 8 },
  miniCard: {
    flex: 1,
    borderRadius: 12,
    borderWidth: 1,
    borderColor: 'rgba(255,255,255,0.1)',
    backgroundColor: 'rgba(255,255,255,0.04)',
    paddingVertical: 10,
    paddingHorizontal: 8,
    alignItems: 'center',
  },
  miniVal: { color: '#fff', fontWeight: '700', fontSize: 13 },
  miniLbl: { marginTop: 2, color: 'rgba(255,255,255,0.52)', fontSize: 10, textAlign: 'center' },

  chatFab: {
    position: 'absolute',
    right: 16,
    bottom: 132,
