import { useEffect } from 'react';
import useChat from '../hooks/useChat';
import ChatBubble from '../components/ChatBubble';
import ChatInput from '../components/ChatInput';
import { resolveBookingState } from '../resolveBookingState';

export default function ChatScreen({ booking, myUserId, onClose }) {
  const { canChat, messages, loading, sending, error, sendMessage, markRead } = useChat(booking, myUserId);

  useEffect(() => {
    const resolved = resolveBookingState(booking, myUserId);
    const status = String(booking?.status || '').toUpperCase();
    const allowed = status === 'BOOKED' || status === 'CONFIRMED' || status === 'STARTED';
    if (!allowed || resolved.screen === 'HOME') {
      onClose?.();
    }
  }, [booking, myUserId, onClose]);

  useEffect(() => {
    void markRead();
  }, [messages.length]);

  return (
    <div className="fixed inset-0 z-[1200] flex flex-col bg-[linear-gradient(180deg,rgba(2,6,23,0.96),rgba(15,23,42,0.94))]">
      <div className="flex items-center justify-between border-b border-white/10 px-4 pb-3 pt-[calc(env(safe-area-inset-top,0px)+0.6rem)] backdrop-blur-md">
        <div>
          <p className="text-sm font-bold text-white">Booking Chat</p>
          <p className="text-xs text-gray-400">{booking?.id || '-'}</p>
        </div>
        <button onClick={onClose} className="rounded-[14px] border border-white/10 bg-white/5 px-3 py-1 text-xs text-gray-300 hover:bg-white/10">Close</button>
      </div>

      <div className="flex-1 space-y-2 overflow-y-auto p-3">
        {loading && <p className="text-xs text-cyan-300">Loading messages...</p>}
        {!loading && messages.length === 0 && <p className="text-xs text-gray-500">No messages yet.</p>}
        {messages.map((m) => (
          <ChatBubble key={m.id} message={m} isMine={m.senderId === myUserId} />
        ))}
        {error && <p className="text-xs text-red-300">{error}</p>}
      </div>

      <ChatInput disabled={!canChat} sending={sending} onSend={sendMessage} />
    </div>
  );
}

import { useEffect, useMemo, useState } from 'react';
import api from '../api';
import { useStore } from '../store';
import { resolveBookingState } from '../resolveBookingState';
import { Card, Button } from '../components';
import VerifiedBadge from '../components/VerifiedBadge';

function emptyStatus() {
  return {
    status: 'UNVERIFIED',
    documentType: null,
    frontUrl: '',
    backUrl: '',
    submittedAt: null,
    reviewedAt: null,
    rejectionReason: null
  };
}

export default function KYCScreen({ onBack, onStatusChange }) {
  const { user, activeBooking } = useStore();
  const [statusData, setStatusData] = useState(emptyStatus());
  const [documentType, setDocumentType] = useState('aadhaar');
  const [frontFile, setFrontFile] = useState(null);
  const [backFile, setBackFile] = useState(null);
  const [loading, setLoading] = useState(false);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    resolveBookingState(activeBooking, user);
  }, [activeBooking, user]);

  const loadStatus = async () => {
    if (!user) return;
    setLoading(true);
    setError('');
    try {
      const res = await api.get(`/api/kyc/status?userId=${encodeURIComponent(user)}`);
      const next = res.data?.kyc || emptyStatus();
      setStatusData(next);
      if (next.documentType) {
        setDocumentType(next.documentType);
      }
      if (typeof onStatusChange === 'function') {
        onStatusChange(next);
      }
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to load KYC status');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadStatus();
  }, [user]);

  const canSubmit = useMemo(() => {
    return statusData.status === 'UNVERIFIED' || statusData.status === 'REJECTED';
  }, [statusData.status]);

  const submit = async () => {
    if (!user) {
      setError('Please sign in again.');
      return;
    }

    if (!frontFile) {
      setError('Please upload the front image.');
      return;
    }

    if (documentType === 'aadhaar' && !backFile) {
      setError('Please upload the back image for Aadhaar.');
      return;
    }

    setSubmitting(true);
    setError('');
    try {
      const formData = new FormData();
      formData.append('userId', user);
      formData.append('documentType', documentType);
      formData.append('front', frontFile);
      if (backFile) formData.append('back', backFile);

      const res = await api.post('/api/kyc/submit', formData, {
        headers: {
          'Content-Type': 'multipart/form-data'
        }
      });

      const next = res.data?.kyc || emptyStatus();
      setStatusData(next);
      setFrontFile(null);
      setBackFile(null);
      if (typeof onStatusChange === 'function') {
        onStatusChange(next);
      }
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to submit documents');
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <div>
          <p className="text-[11px] font-semibold uppercase tracking-[0.18em] text-slate-400">KYC center</p>
          <h3 className="text-xl font-black text-white">Identity Verification</h3>
        </div>
        <button onClick={onBack} className="glass-surface rounded-[16px] px-3 py-2 text-sm font-semibold text-cyan-300">Back</button>
      </div>

      <Card>
        {statusData.status === 'VERIFIED' ? (
          <div className="flex items-center gap-2">
            <VerifiedBadge />
            <p className="text-sm text-emerald-300">Your identity has been verified.</p>
          </div>
        ) : (
          <p className="text-sm text-gray-300">Current status: <span className="font-semibold text-white">{statusData.status}</span></p>
        )}

        {statusData.status === 'PENDING' && (
          <p className="mt-2 text-sm text-amber-300">Your documents are under manual review. Re-submission is disabled until review is complete.</p>
        )}

        {statusData.status === 'REJECTED' && statusData.rejectionReason && (
          <p className="mt-2 rounded-lg border border-red-700 bg-red-900/30 px-3 py-2 text-sm text-red-300">
            Rejected: {statusData.rejectionReason}
          </p>
        )}

        {loading && <p className="mt-3 text-sm text-gray-400">Loading KYC status...</p>}
        {error && <p className="mt-3 text-sm text-red-400">{error}</p>}
      </Card>

      <Card className="overflow-hidden">
        <h4 className="mb-3 text-base font-bold text-cyan-300">Submit documents</h4>

        <label className="mb-2 block text-sm text-gray-300">Document type</label>
        <select
          value={documentType}
          onChange={(e) => setDocumentType(e.target.value)}
          disabled={!canSubmit || submitting}
          className="mb-4 w-full rounded-[16px] border border-white/10 bg-slate-950/70 px-3 py-2 text-sm text-white"
        >
          <option value="aadhaar">Aadhaar</option>
          <option value="driving_licence">Driving licence</option>
        </select>

        <label className="mb-1 block text-sm text-gray-300">Front image</label>
        <input
          type="file"
          accept="image/*"
          disabled={!canSubmit || submitting}
          onChange={(e) => setFrontFile(e.target.files?.[0] || null)}
          className="mb-4 w-full rounded-[16px] border border-white/10 bg-slate-950/70 px-3 py-2 text-sm text-white"
        />

        <label className="mb-1 block text-sm text-gray-300">Back image {documentType === 'aadhaar' ? '(required)' : '(optional)'}</label>
        <input
          type="file"
          accept="image/*"
          disabled={!canSubmit || submitting}
          onChange={(e) => setBackFile(e.target.files?.[0] || null)}
          className="mb-4 w-full rounded-[16px] border border-white/10 bg-slate-950/70 px-3 py-2 text-sm text-white"
        />

        <Button onClick={submit} disabled={!canSubmit || submitting || loading}>
          {submitting ? 'Submitting...' : 'Submit for verification'}
        </Button>
      </Card>
    </div>
  );
}

import React, { useMemo, useState } from 'react';
import { Animated, Dimensions, PanResponder, Pressable, StyleSheet, Text, View } from 'react-native';
import { useI18n } from '../i18n';

export default function OnboardingScreen({ isFirstInstall = true, onComplete }) {
  const { t } = useI18n();
  const [activeIndex, setActiveIndex] = useState(0);
  const [dragDx, setDragDx] = useState(0);
  const [panX] = useState(() => new Animated.Value(0));
  const windowWidth = Dimensions.get('window').width;

  function tx(key, fallback) {
    const val = t(key);
    return val === key ? fallback : val;
  }

  const slides = [
    {
      key: 'find-charger',
      title: tx('onboarding.slide1.title', 'Find a Charger Near You'),
      subtitle: tx('onboarding.slide1.subtitle', 'αñ¬αñ╛αñ╕ αñ«αÑçαñé αñÜαñ╛αñ░αÑìαñ£αñ░ αñûαÑïαñ£αÑçαñé'),
      Illustration: MapPinsIllustration,
    },
    {
      key: 'share-earn',
      title: tx('onboarding.slide2.title', 'Share Your Charger, Earn Money'),
      subtitle: tx('onboarding.slide2.subtitle', 'αñàαñ¬αñ¿αñ╛ αñÜαñ╛αñ░αÑìαñ£αñ░ αñ╢αÑçαñ»αñ░ αñòαñ░αÑçαñé, αñ¬αÑêαñ╕αÑç αñòαñ«αñ╛αñÅαñé'),
      Illustration: HomeEarningsIllustration,
    },
    {
      key: 'safe-fast-cashless',
      title: tx('onboarding.slide3.title', 'Safe, Fast, Cashless'),
      subtitle: tx('onboarding.slide3.subtitle', 'αñ╕αÑüαñ░αñòαÑìαñ╖αñ┐αññ, αññαÑçαñ£αñ╝, αñòαÑêαñ╢αñ▓αÑçαñ╕'),
      Illustration: ShieldChargeIllustration,
    },
  ];

  const isLast = activeIndex === slides.length - 1;
  const activeSlide = slides[activeIndex];

  function goNext() {
    if (isLast) {
      onComplete?.();
      return;
    }
    setActiveIndex((v) => Math.min(v + 1, slides.length - 1));
  }

  function goPrev() {
    setActiveIndex((v) => Math.max(v - 1, 0));
  }

  const panResponder = useMemo(
    // eslint-disable-next-line react-hooks/preserve-manual-memoization
    () =>
      PanResponder.create({
        onMoveShouldSetPanResponder: (_, gestureState) =>
          Math.abs(gestureState.dx) > 8 && Math.abs(gestureState.dx) > Math.abs(gestureState.dy),
        onPanResponderMove: (_, gestureState) => {
          panX.setValue(gestureState.dx);
          setDragDx(gestureState.dx);
        },
        onPanResponderRelease: (_, gestureState) => {
          const threshold = 52;
          if (gestureState.dx < -threshold) {
            goNext();
          } else if (gestureState.dx > threshold) {
            goPrev();
          }
          Animated.spring(panX, {
            toValue: 0,
            useNativeDriver: true,
            friction: 8,
            tension: 90,
          }).start();
          setDragDx(0);
        },
        onPanResponderTerminate: () => {
          Animated.spring(panX, {
            toValue: 0,
            useNativeDriver: true,
            friction: 8,
            tension: 90,
          }).start();
          setDragDx(0);
        },
      }),
    [panX, isLast, onComplete, windowWidth]
  );

  if (!isFirstInstall) return null;

  const translateBase = -activeIndex * windowWidth;
  const logicalIndex = activeIndex - dragDx / windowWidth;

  return (
    <View style={styles.container}>
      <View style={styles.topRow}>
        <View />
        <Pressable onPress={() => onComplete?.()} style={styles.skipGhostBtn}>
          <Text style={styles.skipText}>{tx('onboarding.skip', 'Skip')}</Text>
        </Pressable>
      </View>

      <View style={styles.topIllustrationWrap} {...panResponder.panHandlers}>
        <Animated.View
          style={{
            flexDirection: 'row',
            width: windowWidth * slides.length,
            transform: [{ translateX: Animated.add(new Animated.Value(translateBase), panX) }],
          }}
        >
          {slides.map((slide, idx) => {
            const distance = Math.abs(idx - logicalIndex);
            const opacity = Math.max(0.45, 1 - distance * 0.55);
            const parallax = idx === activeIndex ? dragDx * 0.7 : 0;
            return (
              <Animated.View
                key={slide.key}
                style={{
                  width: windowWidth,
                  alignItems: 'center',
                  justifyContent: 'center',
                  opacity,
                }}
              >
                <Animated.View style={{ transform: [{ translateX: parallax }] }}>
                  <slide.Illustration />
                </Animated.View>
              </Animated.View>
            );
          })}
        </Animated.View>
      </View>

      <View style={styles.bottomWrap}>
        <View style={styles.textBlock}>
          <Text style={styles.title}>{activeSlide.title}</Text>
          <Text style={styles.subtitle}>{activeSlide.subtitle}</Text>
        </View>

        <View style={styles.dotsRow}>
          {slides.map((slide, index) => (
            <Pressable
              key={slide.key}
              onPress={() => setActiveIndex(index)}
              style={[styles.dot, index === activeIndex && styles.dotActive]}
            />
          ))}
        </View>

        {isLast ? (
          <Pressable onPress={goNext} style={[styles.primaryBtn, styles.primaryBtnLastFull]}>
            <Text style={styles.primaryBtnText}>{tx('onboarding.getStarted', 'Get Started')}</Text>
          </Pressable>
        ) : (
          <View style={styles.actionsRowRightOnly}>
            <Pressable onPress={goNext} style={styles.primaryBtnInline}>
              <Text style={styles.primaryBtnText}>{tx('common.next', 'Next')}</Text>
            </Pressable>
          </View>
        )}
      </View>
    </View>
  );
}

