import React, { useCallback, useEffect, useRef, useState } from 'react';
import {
  Animated,
  Easing,
  StyleSheet,
  Text,
  TextInput,
  TouchableOpacity,
  View,
} from 'react-native';
import { useI18n } from '../i18n';

/**
 * Screen 04 ΓÇö PIN Setup (React Native)
 * Props:
 *   onComplete(pin: string) ΓÇö called when PIN is confirmed and matches
 *   loading?: boolean
 */
export default function PINSetupScreen({ onComplete, loading = false }) {
  const { t, locale } = useI18n();
  const isHindi = locale === 'hi';

  function tx(key, fallback) {
    const v = t(key);
    return v === key ? fallback : v;
  }

  const [step, setStep] = useState('enter'); // 'enter' | 'confirm' | 'success'
  const [pin, setPin] = useState('');
  const [confirmPin, setConfirmPin] = useState('');
  const [mismatchMsg, setMismatchMsg] = useState('');

  const enterRef = useRef(null);
  const confirmRef = useRef(null);

  // Animations
  const [shakeX] = useState(() => new Animated.Value(0));
  const [lockGlow] = useState(() => new Animated.Value(0));
  const [headingSlide] = useState(() => new Animated.Value(12));
  const [headingOpacity] = useState(() => new Animated.Value(0));
  const [checkScale] = useState(() => new Animated.Value(0));
  const [checkOpacity] = useState(() => new Animated.Value(0));
  const [stepDotWidth] = useState(() => new Animated.Value(8));

  // Pulsing glow on lock icon
  useEffect(() => {
    const loop = Animated.loop(
      Animated.sequence([
        Animated.timing(lockGlow, { toValue: 1, duration: 1400, easing: Easing.inOut(Easing.sine), useNativeDriver: true }),
        Animated.timing(lockGlow, { toValue: 0, duration: 1400, easing: Easing.inOut(Easing.sine), useNativeDriver: true }),
      ])
    );
    loop.start();
    return () => loop.stop();
  }, [lockGlow]);

  const lockScale = lockGlow.interpolate({ inputRange: [0, 1], outputRange: [1, 1.06] });
  const lockOpacity = lockGlow.interpolate({ inputRange: [0, 1], outputRange: [0.6, 1] });

  // Heading slide-in when step changes
  function animateHeading() {
    headingSlide.setValue(12);
    headingOpacity.setValue(0);
    Animated.parallel([
      Animated.timing(headingSlide, { toValue: 0, duration: 280, easing: Easing.out(Easing.quad), useNativeDriver: true }),
      Animated.timing(headingOpacity, { toValue: 1, duration: 280, easing: Easing.out(Easing.quad), useNativeDriver: true }),
    ]).start();
  }

  useEffect(() => { animateHeading(); }, [step]);

  // Step dot expansion
  useEffect(() => {
    Animated.spring(stepDotWidth, {
      toValue: step === 'confirm' ? 22 : 22,
      useNativeDriver: false,
    }).start();
  }, [step]);

  // Auto-advance to confirm when 4 digits entered
  useEffect(() => {
    if (step === 'enter' && pin.length === 4) {
      const id = setTimeout(() => {
        setStep('confirm');
        confirmRef.current?.focus();
      }, 300);
      return () => clearTimeout(id);
    }
  }, [pin, step]);

  // Verify when confirm hits 4 digits
  const verify = useCallback(() => {
    if (confirmPin.length !== 4 || loading) return;
    if (confirmPin === pin) {
      // Success animation
      Animated.parallel([
        Animated.spring(checkScale, { toValue: 1, friction: 5, tension: 120, useNativeDriver: true }),
        Animated.timing(checkOpacity, { toValue: 1, duration: 200, useNativeDriver: true }),
      ]).start();
      setStep('success');
      setTimeout(() => onComplete?.(pin), 800);
    } else {
      // Shake + reset
      Animated.sequence([
        Animated.timing(shakeX, { toValue: -10, duration: 60, useNativeDriver: true }),
        Animated.timing(shakeX, { toValue: 10, duration: 60, useNativeDriver: true }),
        Animated.timing(shakeX, { toValue: -8, duration: 60, useNativeDriver: true }),
        Animated.timing(shakeX, { toValue: 8, duration: 60, useNativeDriver: true }),
        Animated.timing(shakeX, { toValue: -4, duration: 60, useNativeDriver: true }),
        Animated.timing(shakeX, { toValue: 0, duration: 60, useNativeDriver: true }),
      ]).start(() => {
        setMismatchMsg(isHindi ? 'PINs αñ«αÑçαñ▓ αñ¿αñ╣αÑÇαñé αñûαñ╛αññαÑç, αñ½αñ┐αñ░ αñòαÑïαñ╢αñ┐αñ╢ αñòαñ░αÑçαñé' : "PINs don't match, try again");
        setTimeout(() => {
          setPin('');
          setConfirmPin('');
          setStep('enter');
          setMismatchMsg('');
          enterRef.current?.focus();
        }, 600);
      });
    }
  }, [confirmPin, pin, loading, isHindi, onComplete, shakeX, checkScale, checkOpacity]);

  useEffect(() => {
    if (step === 'confirm' && confirmPin.length === 4) {
      const id = setTimeout(() => verify(), 0);
      return () => clearTimeout(id);
    }
  }, [confirmPin, step, verify]);

  function handlePinChange(text) {
    const digits = text.replace(/\D/g, '').slice(0, 4);
    setPin(digits);
  }

  function handleConfirmChange(text) {
    const digits = text.replace(/\D/g, '').slice(0, 4);
    setConfirmPin(digits);
  }

  function renderBoxes(currentPin) {
    return (
      <View style={s.boxRow}>
        {[0, 1, 2, 3].map((i) => {
          const filled = i < currentPin.length;
          return (
            <View
              key={i}
              style={[
                s.box,
                filled && s.boxFilled,
              ]}
            >
              <View style={[s.dot, { opacity: filled ? 1 : 0 }]} />
            </View>
          );
        })}
      </View>
    );
  }

  const stepLabel = step === 'enter' || step === 'success'
    ? (isHindi ? 'αñÜαñ░αñú 1 / 2' : 'Step 1 of 2')
    : (isHindi ? 'αñÜαñ░αñú 2 / 2' : 'Step 2 of 2');

  const headingText = step === 'confirm'
    ? tx('pin.confirmHeading', isHindi ? 'PIN αñòαÑÇ αñ¬αÑüαñ╖αÑìαñƒαñ┐ αñòαñ░αÑçαñé' : 'Confirm your PIN')
    : tx('pin.setHeading', isHindi ? 'αñàαñ¬αñ¿αñ╛ αñ╕αÑüαñ░αñòαÑìαñ╖αñ┐αññ PIN αñ╕αÑçαñƒ αñòαñ░αÑçαñé' : 'Set your secure PIN');

  const subtextText = step === 'confirm'
    ? tx('pin.confirmSubtext', isHindi ? 'PIN αñªαÑïαñ¼αñ╛αñ░αñ╛ αñªαñ░αÑìαñ£ αñòαñ░αÑçαñé' : 'Re-enter your PIN to confirm')
    : tx('pin.setSubtext', isHindi ? 'αñÉαñ¬ αñòαÑï αñ£αñ▓αÑìαñªαÑÇ αñàαñ¿αñ▓αÑëαñò αñòαñ░αñ¿αÑç αñòαÑç αñ▓αñ┐αñÅ αñëαñ¬αñ»αÑïαñù αñòαñ┐αñ»αñ╛ αñ£αñ╛αñÅαñùαñ╛' : 'Used to unlock the app quickly');

  const activePin = step === 'enter' ? pin : confirmPin;

  return (
    <View style={s.page}>
      {/* Lock Icon */}
      <View style={s.iconWrap}>
        <Animated.View
          style={[
            s.glowRing,
            { opacity: lockOpacity, transform: [{ scale: lockScale }] },
          ]}
        />
        {/* SVG-equivalent lock drawn with Views */}
        <View style={s.lockBody}>
          <View style={s.lockShackle} />
          <View style={s.keyhole} />
          <View style={s.keyholePin} />
        </View>
        {/* Success checkmark overlay */}
        {step === 'success' && (
          <Animated.View
            style={[
              s.checkmarkOverlay,
              { opacity: checkOpacity, transform: [{ scale: checkScale }] },
            ]}
          >
            <View style={s.checkCircle}>
              <Text style={s.checkMark}>Γ£ô</Text>
            </View>
          </Animated.View>
        )}
      </View>

      {/* Step indicator */}
      <View style={s.stepRow}>
        {[0, 1].map((i) => {
          const active = step === 'enter' ? i === 0 : i === 1;
          const done = step === 'confirm' && i === 0;
          return (
            <Animated.View
              key={i}
              style={[
                s.stepDot,
                {
                  width: active ? 22 : 8,
                  opacity: active ? 1 : done ? 0.7 : 0.35,
                  backgroundColor: (active || done) ? '#00D4AA' : 'rgba(255,255,255,0.25)',
                },
              ]}
            />
          );
        })}
      </View>
      <Text style={s.stepLabel}>{stepLabel}</Text>

      {/* Heading */}
      <Animated.Text
        style={[
          s.heading,
          { opacity: headingOpacity, transform: [{ translateY: headingSlide }] },
        ]}
      >
        {headingText}
      </Animated.Text>
      <Text style={s.subtext}>{subtextText}</Text>

      {/* PIN boxes + hidden TextInput */}
      <Animated.View style={[s.boxesWrap, { transform: [{ translateX: shakeX }] }]}>
        {renderBoxes(activePin)}
        {step === 'enter' && (
          <TextInput
            ref={enterRef}
            value={pin}
            onChangeText={handlePinChange}
            keyboardType="number-pad"
            maxLength={4}
            secureTextEntry
            autoFocus
            style={s.hiddenInput}
            editable={!loading && !successAnim}
          />
        )}
        {step === 'confirm' && (
          <TextInput
            ref={confirmRef}
            value={confirmPin}
            onChangeText={handleConfirmChange}
            keyboardType="number-pad"
            maxLength={4}
            secureTextEntry
            style={s.hiddenInput}
            editable={!loading}
          />
        )}
      </Animated.View>

      {/* Status text */}
      {mismatchMsg ? (
        <Text style={s.errorText}>{mismatchMsg}</Text>
      ) : (
        <Text style={s.hintText}>
          {tx('pin.hint', isHindi ? '4 αñàαñéαñòαÑïαñé αñòαñ╛ PIN αñªαñ░αÑìαñ£ αñòαñ░αÑçαñé' : 'Enter a 4-digit PIN')}
        </Text>
      )}

      {loading && (
        <Text style={s.loadingText}>
          {tx('pin.saving', isHindi ? 'PIN αñ╕αÑçαñ╡ αñ╣αÑï αñ░αñ╣αñ╛ αñ╣αÑê...' : 'Saving PIN...')}
        </Text>
      )}
    </View>
  );
}

// Alias to avoid undefined reference in JSX (React Native has no CSS)
const successAnim = false; // always false at module level; component uses step === 'success'

const s = StyleSheet.create({
  page: {
    flex: 1,
    backgroundColor: '#0A0A0F',
    alignItems: 'center',
    justifyContent: 'center',
    paddingHorizontal: 24,
    paddingVertical: 40,
  },

  // Lock icon
  iconWrap: {
    width: 96,
    height: 96,
    alignItems: 'center',
    justifyContent: 'center',
    marginBottom: 28,
    position: 'relative',
  },
  glowRing: {
    position: 'absolute',
    width: 96,
    height: 96,
    borderRadius: 48,
    backgroundColor: 'rgba(0,212,170,0.18)',
  },
  lockBody: {
    width: 48,
    height: 36,
    borderRadius: 8,
    borderWidth: 2,
    borderColor: '#00D4AA',
    backgroundColor: 'rgba(0,212,170,0.12)',
    alignItems: 'center',
    justifyContent: 'center',
    marginTop: 18,
  },
  lockShackle: {
    position: 'absolute',
    top: -18,
    width: 28,
    height: 20,
    borderTopLeftRadius: 14,
    borderTopRightRadius: 14,
    borderWidth: 2.5,
    borderColor: '#00D4AA',
    borderBottomWidth: 0,
    backgroundColor: 'transparent',
  },
  keyhole: {
    width: 10,
    height: 10,
    borderRadius: 5,
    backgroundColor: '#00D4AA',
    marginTop: -2,
  },
  keyholePin: {
    width: 5,
    height: 7,
    borderRadius: 2,
    backgroundColor: '#00D4AA',
    marginTop: 1,
  },
  checkmarkOverlay: {
    position: 'absolute',
    inset: 0,
    top: 0,
    left: 0,
    right: 0,
    bottom: 0,
    alignItems: 'center',
    justifyContent: 'center',
    backgroundColor: '#0A0A0F',
    borderRadius: 48,
  },
  checkCircle: {
    width: 52,
    height: 52,
    borderRadius: 26,
    backgroundColor: '#00D4AA',
    alignItems: 'center',
    justifyContent: 'center',
  },
  checkMark: {
    color: '#0A0A0F',
    fontSize: 26,
    fontWeight: '700',
  },

  // Step indicator
  stepRow: {
    flexDirection: 'row',
    gap: 6,
    alignItems: 'center',
    marginBottom: 4,
  },
  stepDot: {
    height: 8,
    borderRadius: 9999,
    backgroundColor: '#00D4AA',
  },
  stepLabel: {
    fontSize: 11,
    color: 'rgba(255,255,255,0.45)',
    letterSpacing: 1,
    textTransform: 'uppercase',
    marginBottom: 20,
  },

  // Heading
  heading: {
    fontSize: 22,
    fontWeight: '700',
    color: '#FFFFFF',
    marginBottom: 8,
    textAlign: 'center',
  },
  subtext: {
    fontSize: 14,
    color: 'rgba(255,255,255,0.5)',
    marginBottom: 36,
    textAlign: 'center',
    maxWidth: 260,
    lineHeight: 21,
  },

  // PIN boxes
  boxesWrap: {
    marginBottom: 20,
  },
  boxRow: {
    flexDirection: 'row',
    gap: 14,
    justifyContent: 'center',
  },
  box: {
    width: 58,
    height: 66,
    borderRadius: 14,
    borderWidth: 2,
    borderColor: 'rgba(255,255,255,0.15)',
    backgroundColor: 'rgba(255,255,255,0.04)',
    alignItems: 'center',
    justifyContent: 'center',
  },
  boxFilled: {
    borderColor: '#00D4AA',
    backgroundColor: 'rgba(0,212,170,0.08)',
  },
  dot: {
    width: 14,
    height: 14,
    borderRadius: 7,
    backgroundColor: '#00D4AA',
  },
  hiddenInput: {
    position: 'absolute',
    width: 1,
    height: 1,
    opacity: 0,
  },

  // Status text
  errorText: {
    fontSize: 13,
    color: '#FF4D6A',
    textAlign: 'center',
    marginBottom: 16,
    fontWeight: '500',
  },
  hintText: {
    fontSize: 13,
    color: 'rgba(255,255,255,0.35)',
    textAlign: 'center',
    marginBottom: 16,
  },
  loadingText: {
    fontSize: 13,
    color: 'rgba(255,255,255,0.5)',
    marginTop: 8,
  },
});

import React, { useCallback, useEffect, useRef, useState } from 'react';
import { useI18n } from '../i18n';
import { useTheme } from '../hooks/useTheme';
import { useStore } from '../store';

const MAX_ATTEMPTS = 5;

export default function UnlockScreen({ user = {}, onUnlock, onUsePhone, biometricAvailable = false, onBiometric, loading = false }) {
  const { t, locale } = useI18n();
  const { c } = useTheme();
  const { verifyPin } = useStore();
  const isHindi = locale === 'hi';

  const [pin, setPin] = useState('');
  const [attempts, setAttempts] = useState(0);
  const [error, setError] = useState('');
  const [bioStatus, setBioStatus] = useState('idle');
  const [fadeOut, setFadeOut] = useState(false);
  const refs = useRef([]);

  function tx(key, fallback) {
    const value = t(key);
    return value === key ? fallback : value;
  }

  const triggerBiometric = useCallback(async () => {
    if (!biometricAvailable || !onBiometric) return;
    setBioStatus('prompting');
    try {
      const ok = await onBiometric();
      if (ok) {
        setFadeOut(true);
        setTimeout(() => onUnlock?.(), 400);
      } else {
        setBioStatus('failed');
      }
    } catch {
      setBioStatus('failed');
    }
  }, [biometricAvailable, onBiometric, onUnlock]);

  useEffect(() => {
    const id = setTimeout(() => triggerBiometric(), 0);
    return () => clearTimeout(id);
  }, [triggerBiometric]);

  useEffect(() => {
    const digits = pin.replace(/\D/g, '').slice(0, 4);
    if (digits !== pin) {
      setTimeout(() => setPin(digits), 0);
      return;
    }
    if (digits.length !== 4 || loading || attempts >= MAX_ATTEMPTS) return;
    setTimeout(async () => {
      const matched = await verifyPin(digits);
      if (matched) {
        setFadeOut(true);
        setTimeout(() => onUnlock?.(), 400);
        return;
      }
      const next = attempts + 1;
      setAttempts(next);
      setPin('');
      setError(next >= MAX_ATTEMPTS
        ? tx('unlock.lockout', isHindi ? 'αñ¼αñ╣αÑüαññ αñàαñºαñ┐αñò αñùαñ▓αññ αñ¬αÑìαñ░αñ»αñ╛αñ╕αÑñ αñ½αñ╝αÑïαñ¿ αñ¿αñéαñ¼αñ░ αñ╕αÑç αñ▓αÑëαñùαñ┐αñ¿ αñòαñ░αÑçαñéαÑñ' : 'Too many wrong attempts. Please use phone instead.')
        : tx('unlock.wrongPin', isHindi ? 'αñùαñ▓αññ PIN, αñ½αñ┐αñ░ αñòαÑïαñ╢αñ┐αñ╢ αñòαñ░αÑçαñéαÑñ' : 'Wrong PIN, try again.'));
      refs.current[0]?.focus();
    }, 0);
  }, [pin, loading, attempts, verifyPin, onUnlock, t, isHindi]);

  const lockout = attempts >= MAX_ATTEMPTS;
  const firstName = (user?.displayName ?? '').split(' ')[0] || tx('unlock.user', 'User');

  return (
    <div style={{ minHeight: '100vh', background: c.page, color: c.text, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 24, opacity: fadeOut ? 0 : 1, transition: 'opacity 400ms ease' }}>
      <div style={{ width: '100%', maxWidth: 420, background: c.surface, border: `1px solid ${c.border}`, borderRadius: 20, padding: 20, textAlign: 'center' }}>
        <p style={{ color: c.textMuted }}>{tx('unlock.greeting', isHindi ? 'αñ╡αñ╛αñ¬αñ╕ αñåαñÅ,' : 'Welcome back,')} <strong style={{ color: c.text }}>{firstName}</strong></p>

        {!lockout && (
          <>
            <p style={{ color: c.textSoft }}>{tx('unlock.enterPin', isHindi ? 'PIN αñªαñ░αÑìαñ£ αñòαñ░αÑçαñé' : 'Enter your PIN')}</p>
            <div style={{ display: 'flex', justifyContent: 'center', gap: 12 }}>
              {[0, 1, 2, 3].map((i) => {
                const filled = i < pin.length;
                return (
                  <div key={i} style={{ width: 54, height: 62, borderRadius: 12, border: `2px solid ${filled ? c.brandPrimary : c.border}`, background: filled ? c.brandPrimarySoft : 'transparent', position: 'relative' }}>
                    <div style={{ width: 12, height: 12, borderRadius: '50%', background: c.brandPrimary, opacity: filled ? 1 : 0, position: 'absolute', left: '50%', top: '50%', transform: 'translate(-50%, -50%)' }} />
                    <input
                      ref={(el) => (refs.current[i] = el)}
                      type="password"
                      inputMode="numeric"
                      maxLength={1}
                      value={filled ? 'ΓÇó' : ''}
                      onChange={(e) => {
                        const d = e.target.value.replace(/\D/g, '').slice(-1);
                        const arr = pin.padEnd(4, ' ').split('');
                        arr[i] = d || ' ';
                        setPin(arr.join('').replace(/\s+$/g, ''));
                        if (d && i < 3) refs.current[i + 1]?.focus();
                      }}
                      disabled={loading || fadeOut}
                      style={{ position: 'absolute', inset: 0, opacity: 0, border: 'none', background: 'transparent' }}
                    />
                  </div>
                );
              })}
            </div>

            {biometricAvailable && (
              <button type="button" onClick={triggerBiometric} disabled={bioStatus === 'prompting' || loading || fadeOut} style={{ marginTop: 14, borderRadius: 12, border: `1px solid ${c.brandPrimary}`, background: c.brandPrimarySoft, color: c.brandPrimary, padding: '10px 14px' }}>
                {bioStatus === 'prompting'
                  ? tx('unlock.scanning', isHindi ? 'αñ╕αÑìαñòαÑêαñ¿ αñ╣αÑï αñ░αñ╣αñ╛ αñ╣αÑêΓÇª' : 'ScanningΓÇª')
                  : tx('unlock.useBiometric', isHindi ? 'αñ¼αñ╛αñ»αÑïαñ«αÑçαñƒαÑìαñ░αñ┐αñò αñ╕αÑç αñàαñ¿αñ▓αÑëαñò αñòαñ░αÑçαñé' : 'Use Biometric')}
              </button>
            )}
          </>
        )}

        {error && <p style={{ color: c.error, marginTop: 14 }}>{error}</p>}

        <button
          type="button"
          onClick={() => onUsePhone?.()}
          disabled={loading || fadeOut}
          style={{ marginTop: lockout ? 24 : 18, border: 'none', background: 'transparent', color: lockout ? c.brandPrimary : c.textSoft, textDecoration: 'underline' }}
        >
          {tx('unlock.usePhone', isHindi ? 'αñ½αñ╝αÑïαñ¿ αñ¿αñéαñ¼αñ░ αñ╕αÑç αñ▓αÑëαñùαñ┐αñ¿ αñòαñ░αÑçαñé' : 'Use phone number instead')}
        </button>
      </div>
    </div>
  );
}
